"use client";

import { useState } from "react";
import { Driver } from "@prisma/client";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { driverSchema, DriverFormValues } from "@/lib/validations";
import { createDriver, deleteDriver } from "@/server/actions/driver.actions";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";

export const columns: ColumnDef<Driver>[] = [
  {
    accessorKey: "category",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Category</span>,
  },
  {
    accessorKey: "name",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Driver Name</span>,
  },
  {
    accessorKey: "licenseNumber",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">License No</span>,
  },
  {
    accessorKey: "status",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Status</span>,
    cell: ({ row }) => {
      const status = row.getValue("status") as string;
      return (
        <span className={`px-2.5 py-1 rounded-full text-[10px] uppercase font-bold tracking-wider ${
          status === 'available' ? 'bg-[#2eb85c]/10 text-[#2eb85c]' :
          status === 'off_duty' ? 'bg-[#f9b115]/10 text-[#f9b115]' :
          status === 'on_trip' ? 'bg-[#3399ff]/10 text-[#3399ff]' :
          'bg-[#e55353]/10 text-[#e55353]'
        }`}>
          {status.replace("_", " ")}
        </span>
      );
    }
  },
  {
    accessorKey: "safetyScore",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Safety Score</span>,
    cell: ({ row }) => {
      const score = row.getValue("safetyScore") as number;
      let color = "text-[#e55353]";
      if (score >= 90) color = "text-[#2eb85c]";
      else if (score >= 70) color = "text-[#f9b115]";
      
      return (
        <div className="flex items-center gap-2">
          <div className="w-16 h-2 rounded-full bg-muted overflow-hidden">
            <div 
              className={`h-full ${color.replace("text-", "bg-")}`} 
              style={{ width: `${score}%` }} 
            />
          </div>
          <span className={`font-semibold ${color}`}>{score}</span>
        </div>
      );
    }
  },
  {
    id: "actions",
    cell: ({ row }) => {
      const driver = row.original;
      return (
        <Button variant="ghost" size="sm" onClick={async () => {
          if (confirm("Are you sure?")) {
            await deleteDriver(driver.id);
          }
        }}>
          Delete
        </Button>
      );
    },
  },
];

export function DriverClient({ data }: { data: Driver[] }) {
  const [open, setOpen] = useState(false);
  const [error, setError] = useState("");

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  const {
    register,
    handleSubmit,
    control,
    reset,
    formState: { errors, isSubmitting },
  } = useForm<DriverFormValues>({
    resolver: zodResolver(driverSchema) as any,
    defaultValues: {
      status: "available",
    }
  });

  const onSubmit = async (values: DriverFormValues) => {
    setError("");
    const result = await createDriver(values);
    if (result.success) {
      setOpen(false);
      reset();
    } else {
      setError(result.error || "Failed to create driver");
    }
  };

  return (
    <Card className="shadow-sm border-border overflow-hidden">
      <CardHeader className="border-b bg-card px-6 py-4 flex flex-row items-center justify-between">
        <div>
          <CardTitle className="text-xl font-medium tracking-tight">Driver Registry</CardTitle>
          <p className="text-sm text-muted-foreground mt-1">
            Manage your drivers, licenses, and safety scores.
          </p>
        </div>
        <Dialog open={open} onOpenChange={setOpen}>
          <DialogTrigger render={<Button />}>
            Add Driver
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add New Driver</DialogTitle>
            </DialogHeader>
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
              {error && <p className="text-sm text-red-500">{error}</p>}
              
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Full Name</Label>
                  <Input {...register("name")} />
                  {errors.name && <p className="text-xs text-red-500">{errors.name.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>License Number</Label>
                  <Input {...register("licenseNumber")} />
                  {errors.licenseNumber && <p className="text-xs text-red-500">{errors.licenseNumber.message}</p>}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Category</Label>
                  <Controller
                    control={control}
                    name="category"
                    render={({ field }) => (
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select category" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="LMV">LMV (Light)</SelectItem>
                          <SelectItem value="HMV">HMV (Heavy)</SelectItem>
                        </SelectContent>
                      </Select>
                    )}
                  />
                  {errors.category && <p className="text-xs text-red-500">{errors.category.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>License Expiry</Label>
                  <Input type="date" {...register("licenseExpiry")} />
                  {errors.licenseExpiry && <p className="text-xs text-red-500">{errors.licenseExpiry.message}</p>}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Contact Phone</Label>
                  <Input {...register("contact")} />
                  {errors.contact && <p className="text-xs text-red-500">{errors.contact.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>Status</Label>
                  <Controller
                    control={control}
                    name="status"
                    render={({ field }) => (
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select status" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="available">Available</SelectItem>
                          <SelectItem value="off_duty">Off Duty</SelectItem>
                          <SelectItem value="suspended">Suspended</SelectItem>
                        </SelectContent>
                      </Select>
                    )}
                  />
                </div>
              </div>

              <Button type="submit" className="w-full" disabled={isSubmitting}>
                {isSubmitting ? "Saving..." : "Save Driver"}
              </Button>
            </form>
          </DialogContent>
        </Dialog>
      </CardHeader>

      <CardContent className="p-0">
        <Table>
          <TableHeader className="bg-muted/30">
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => {
                  return (
                    <TableHead key={header.id} className="h-10">
                      {header.isPlaceholder
                        ? null
                        : flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                    </TableHead>
                  )
                })}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                  className="hover:bg-muted/20 transition-colors"
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="py-3">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center">
                  No drivers found. Click "Add Driver" to register one.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}
